code = """import json
import pandas as pd

# Access variables from previous tool calls
reviews = var_call_ECBqnbMiXYF7hhX4AdoVUM13
books_file_path = var_call_ZFYRrX85nXfIDGYu6KWmVNOM

# Load the full books data from the JSON file
with open(books_file_path, 'r', encoding='utf-8') as f:
    books = json.load(f)

# Build set of mapped book_ids from purchase_ids by replacing prefix
purchase_ids = [r['purchase_id'] for r in reviews]
mapped_book_ids = set()
for pid in purchase_ids:
    if pid.startswith('purchaseid_'):
        mapped_book_ids.add(pid.replace('purchaseid_', 'bookid_'))
    else:
        mapped_book_ids.add(pid)

# Helper to check for English language mention
def has_english_field(book):
    # Check several fields for 'english' or 'language' indicators
    text_fields = []
    for k in ['description', 'details', 'categories', 'author', 'title']:
        v = book.get(k)
        if v is None:
            continue
        # fields may be stored as non-string types; convert
        if not isinstance(v, str):
            try:
                v = json.dumps(v)
            except Exception:
                v = str(v)
        text_fields.append(v)
    combined = '\n'.join(text_fields).lower()
    if 'english' in combined:
        return True
    # also check for patterns like 'language: english' or 'language\u00a0: english'
    if 'language' in combined and 'english' in combined:
        return True
    return False

# Find matching books
matches = []
bookid_to_book = {b.get('book_id'): b for b in books}
for bid in mapped_book_ids:
    book = bookid_to_book.get(bid)
    if not book:
        continue
    # ensure category contains Literature & Fiction
    cats = book.get('categories','')
    cats_str = cats if isinstance(cats, str) else json.dumps(cats)
    if 'literature & fiction' not in cats_str.lower():
        continue
    english = has_english_field(book)
    if not english:
        # if no explicit english mention, try to heuristically detect by checking if title/description contain common English words
        combined = (book.get('title','') + ' ' + (book.get('description') or '')).lower()
        common_english_words = ['the','and','of','to','in','a']
        if sum(1 for w in common_english_words if (' ' + w + ' ') in (' ' + combined + ' ')) >= 2:
            english = True
    if english:
        matches.append({
            'book_id': book.get('book_id'),
            'title': book.get('title'),
            'author': book.get('author'),
            'categories': book.get('categories'),
            'description': book.get('description')
        })

# Prepare output
out = json.dumps(matches)
print("__RESULT__:")
print(out)"""

